import React, { useEffect, useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { useParams, useNavigate } from "react-router-dom";


function ProductDetail()
{
    const navigate = useNavigate();
    const { slug } = useParams(); // Get the 'slug' from the URL
    const [loading, setLoading] = useState(true);
    const [products, setProducts] = useState([]); // Changed from products to product for single item
    const [category, setCategory] = useState([]);

    useEffect(() =>
    {
        let isMounted = true;

        // Use the destructured slugs from the component's useParams
        axios.get(`/api/viewProductDetail/${category}/${slug}`).then(res =>
        {
            if (isMounted)
            {
                console.log(res.data);
                if (res.data.status === 200)
                {
                    setCategory(res.data.category)
                    setProducts(res.data.products)
                    setLoading(false);
                }
                else if (res.data.status === 404)
                {
                    // Use navigate for redirection
                    navigate('/collections');
                    Swal.fire("Warning", res.data.message, "error");
                }
                setLoading(false);
            }
        }).catch(err =>
        {
            if (isMounted)
            {
                console.error("Error fetching products:", err);
                Swal.fire("Error", "Could not fetch data. Please try again later.", "error");
                setLoading(false);
            }
        });

        return () =>
        {
            isMounted = false;
        };
    }, [category, slug, navigate]);

    if (loading)
    {
        return <h4>Loading Products Details...</h4>;
    }
    else if (products.length === 0) // Check product length
    {
        var avail_stock = "";
        if (products.qty <= 0)
        {
            avail_stock =
                <div>
                    <label className="btn-sm btn-danger px-4 mt-2"> In Stock</label>

                    <div className="row">
                        <div className="col-md-3 mt-3">
                            <div className="input-group">
                                <button type="button" className="input-group-text">-</button>
                                <input type="text" className="form-control text-center" />
                                <button type="button" className="input-group-text">+</button>
                            </div>
                        </div>
                        <div className="col-md-9 mt-3">
                            <button type="button" className="btn btn-primary w-100">Add to Cart </button>
                        </div>
                    </div>
                </div >
        }
        else
        {
            avail_stock =
                <div>
                    <label className="btn-sm btn-danger px-4 mt-2"> Out of Stock</label>
                    <div className="row">
                    </div>
                </div >
        }



    }


    return (
        <div>
            <div classname="py-3 bg-warning">
                <div classname="container">
                    <h6>Collections / {category.name} / {products.name}</h6>
                </div>
            </div>

            <div className="py-3">
                <div className="container">
                    <div className="row">

                        {/* Product Details */}
                        <div className="col-md-4 border-end">
                            <img src={`http://localhost:8000/${products.image}`} alt={products.name} className="w-100" />
                        </div>

                        {/* Product Information */}
                        <div className="col-md-8">
                            <h4>
                                {products.name}
                                <span className="float-end badge btn-sm btn-danger badge-pil">
                                    {products.brand}
                                </span>
                            </h4>
                            <p>{products.description}</p>
                            <h4 className="mb-1">
                                KSH: {products.selling_price}
                                <s className="ms-2"> KSH: {products.mrp} </s>
                            </h4>
                            <div>
                                {avail_stock}
                            </div>

                            <button className="btn btn-danger mt-3"> Add to Wishlist </button>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    )
}
export default ProductDetail;
